package com.interview.lld.parking.model;

// в”Ђв”Ђ WHY THIS ENUM в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
// Defines the three standard parking spot sizes. Used for matching vehicles
// to appropriate spots using best-fit allocation.
// рџЋ™пёЏ "Three spot sizes вЂ” compact, large, handicapped. Best-fit means a compact
//     car gets a compact spot if available, not a wasted large spot."

public enum SpotSize {
    COMPACT(1),     // motorcycles, small cars
    LARGE(2),       // SUVs, vans
    HANDICAPPED(2); // accessible spots, same physical size as large

    private final int capacity;

    SpotSize(int capacity) {
        this.capacity = capacity;
    }

    public int getCapacity() {
        return capacity;
    }

    // WHY: best-fit check вЂ” a compact vehicle fits in any spot,
    //      but we prefer the smallest available to avoid waste
    public boolean canFit(SpotSize vehicleSize) {
        return this.capacity >= vehicleSize.capacity;
    }
}

