// в”Ђв”Ђ WHY THIS ENUM в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
// Parking spot lifecycle: AVAILABLE в†’ OCCUPIED в†’ AVAILABLE.
// Only two states needed вЂ” no intermediate "reserved" state since park()
// is atomic with spot allocation.
// рџЋ™пёЏ "Just two states вЂ” available or occupied. Park and unpark flip between them."

public enum SpotStatus {
    AVAILABLE,
    OCCUPIED
}

package com.interview.lld.parking.model;

// в”Ђв”Ђ WHY THIS CLASS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
// Immutable value object representing a vehicle entering the parking lot.
// Only tracks license plate and size вЂ” no owner info, color, etc. (out of scope).
// рџЋ™пёЏ "Vehicle is just license plate plus size. Immutable вЂ” once created, never changes."

public record Vehicle(String licensePlate, SpotSize size) {
    public Vehicle {
        if (licensePlate == null || licensePlate.isBlank()) {
            throw new ParkingException("License plate cannot be empty");
        }
        if (size == null) {
            throw new ParkingException("Vehicle size cannot be null");
        }
    }
}

package com.interview.lld.parking.model;

import java.util.concurrent.locks.ReentrantLock;
import javax.annotation.Nullable;

// в”Ђв”Ђ WHY THIS CLASS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
// The physical parking spot entity. Each spot knows its own status and guards
// its own state transitions through occupy() and release(). Crucially, each
// spot has its own ReentrantLock for fine-grained concurrency control.
// рџЋ™пёЏ "Each spot is a mini state machine. It enforces its own rules вЂ” you can't
//     occupy an already-occupied spot. And each spot has its own lock so
//     different spots can be parked concurrently without blocking each other."

public class ParkingSpot {
    private final String id;
    private final int floorNumber;
    private final SpotSize size;
    private SpotStatus status;
    @Nullable
    private Vehicle currentVehicle;
    private final ReentrantLock lock;  // per-spot fine-grained lock

    public ParkingSpot(String id, int floorNumber, SpotSize size) {
        if (id == null || id.isBlank()) {
            throw new ParkingException("Spot ID cannot be empty");
        }
        if (floorNumber < 0) {
            throw new ParkingException("Floor number cannot be negative");
        }
        if (size == null) {
            throw new ParkingException("Spot size cannot be null");
        }

        this.id = id;
        this.floorNumber = floorNumber;
        this.size = size;
        this.status = SpotStatus.AVAILABLE;
        this.currentVehicle = null;
        this.lock = new ReentrantLock();
    }

    // WHY: expose lock for external acquisition (ThreadSafeParkingService)
    public ReentrantLock getLock() {
        return lock;
    }

    // WHY: occupies this spot with a vehicle вЂ” only succeeds if currently AVAILABLE
    // вљ пёЏ FOLLOW-UP: "What if two threads try to occupy the same spot?"
    //    в†’ "Each spot has its own ReentrantLock. The caller must acquire spot.getLock()
    //       before calling occupy(). Only one thread holds the lock at a time."
    public void occupy(Vehicle vehicle) {
        if (status != SpotStatus.AVAILABLE) {
            throw new SpotAlreadyOccupiedException(
                "Spot " + id + " is already occupied"
            );
        }
        if (!size.canFit(vehicle.size())) {
            throw new SpotSizeMismatchException(
                "Vehicle size " + vehicle.size() + " cannot fit in spot size " + size
            );
        }
        this.status = SpotStatus.OCCUPIED;
        this.currentVehicle = vehicle;
    }

    // WHY: releases the spot back to AVAILABLE вЂ” idempotent (safe to call twice)
    // вљ пёЏ FOLLOW-UP: "Why is this idempotent?"
    //    в†’ "If a cleanup sweep and a real unpark both try to release, the second
    //       one sees AVAILABLE and does nothing. No error, no harm."
    public void release() {
        if (status == SpotStatus.OCCUPIED) {
            this.status = SpotStatus.AVAILABLE;
            this.currentVehicle = null;
        }
        // else: already available, do nothing (idempotent)
    }

    // Getters
    public String getId() {
        return id;
    }

    public int getFloorNumber() {
        return floorNumber;
    }

    public SpotSize getSize() {
        return size;
    }

    public SpotStatus getStatus() {
        return status;
    }

    @Nullable
    public Vehicle getCurrentVehicle() {
        return currentVehicle;
    }

    public boolean isAvailable() {
        return status == SpotStatus.AVAILABLE;
    }
}

package com.interview.lld.parking.model;

import java.time.Instant;

// в”Ђв”Ђ WHY THIS CLASS в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
// Immutable receipt given to the driver after successful parking. Contains
// everything needed to unpark and charge: ticket ID, spot reference, vehicle,
// and entry time for fee calculation.
// рџЋ™пёЏ "The ticket is your receipt. Immutable вЂ” once issued, nothing changes it.
//     Entry time is captured here so we can charge by duration on exit."

public record ParkingTicket(
    String ticketId,
    String spotId,
    Vehicle vehicle,
    Instant entryTime
) {
    public ParkingTicket {
        if (ticketId == null || ticketId.isBlank()) {
            throw new ParkingException("Ticket ID cannot be empty");
        }
        if (spotId == null || spotId.isBlank()) {
            throw new ParkingException("Spot ID cannot be empty");
        }
        if (vehicle == null) {
            throw new ParkingException("Vehicle cannot be null");
        }
        if (entryTime == null) {
            throw new ParkingException("Entry time cannot be null");
        }
    }
}

