// Base exception for the parking domain. All specific exceptions extend this
// so callers can catch the domain family with one handler.
// рџЋ™пёЏ "One base exception for the parking domain. All specific errors extend it."

public class ParkingException extends RuntimeException {
    public ParkingException(String message) {
        super(message);
    }

    public ParkingException(String message, Throwable cause) {
        super(message, cause);
    }
}

package com.interview.lld.parking.model;

// Thrown when no spot of the required size is available
public class NoSpotAvailableException extends ParkingException {
    public NoSpotAvailableException(String message) {
        super(message);
    }
}

package com.interview.lld.parking.model;

// Thrown when trying to occupy an already-occupied spot
public class SpotAlreadyOccupiedException extends ParkingException {
    public SpotAlreadyOccupiedException(String message) {
        super(message);
    }
}

package com.interview.lld.parking.model;

// Thrown when vehicle size doesn't fit in spot size
public class SpotSizeMismatchException extends ParkingException {
    public SpotSizeMismatchException(String message) {
        super(message);
    }
}

package com.interview.lld.parking.model;

// Thrown when ticket ID is not found or invalid
